INSERT INTO public.neuron_templates (name, description, category, blocks_template, is_public, usage_count, default_tags) VALUES ('50 Sensuri în Formule de Comunicare', 'Cele 50 de sensuri fundamentale de comunicare cu structuri PAS, AIDA, FAB, UVA și aplicații practice de copywriting.', 'Codul Cușnir', '[{"type":"heading","content":"50 SENSURI în Formule de Comunicare"},{"type":"text","content":"50 de formule care acoperă toate dimensiunile comunicării persuasive."},{"type":"subheading","content":"Sensuri 1-10: Durere și Soluție"},{"type":"list","content":"1. Rezolvă-ți durerea acum. 2. Ignorarea agravează. 3. Dorințele tale sunt importante. 4. Rezolv exact preocuparea ta. 5. Obține ce dorești. 6. Se potrivește perfect. 7. Cea mai eficientă cale. 8. Oferă mai mult. 9. Nimic asemănător pe piață. 10. Calitate superioară."},{"type":"subheading","content":"Sensuri 11-20: Credibilitate"},{"type":"list","content":"11. Experiența necesară. 12. Alții au reușit. 13. Testat de succes. 14. Eu sunt dovada. 15. Te ghidez pas cu pas. 16. Începe azi. 17. Vei simți putere. 18. Poți conta pe mine. 19. Onestitate. 20. Am fost acolo."},{"type":"subheading","content":"Sensuri 21-30: Urgență"},{"type":"list","content":"21. Preț mic vs valoare mare. 22. Rezultate incomparabile. 23. Alegere greșită costă. 24. Nu rata. 25. Acțiuni rapide. 26. Azi e momentul. 27. Amânare = pierdere. 28. Exclusiv și limitat. 29. Clienții mă caută. 30. Feedback confirmă."},{"type":"subheading","content":"Sensuri 31-50: Valoare și Încredere"},{"type":"list","content":"31-40: Investiție, dedicare, suport, prioritate, experiență, greșeli, împreună, decizii, pasiune, acționează. 41-50: Clienți fericiți, cunoștințe, cheia, motivație, atenție, rezolvăm, timpul trece, nu aștepta, merită, depășește convingeri."},{"type":"divider","content":""},{"type":"subheading","content":"Structuri de Aplicare"},{"type":"idea","content":"PAS: Problem (1,3,20) → Agitate (2,23) → Solve (4,7,9)"},{"type":"idea","content":"AIDA: Attention (6,9) → Interest (21,18) → Desire (27,40) → Action (26,29)"},{"type":"idea","content":"FAB: Features (6,9) → Advantages (22,35) → Benefits (5,31)"},{"type":"idea","content":"UVA: Urgency (26,28) → Value (21,33) → Action (27,47)"}]'::jsonb, true, 0, ARRAY['sensuri','formule','PAS','AIDA','FAB','UVA']);